const TicketPricing=(()=>{const t=10,o=1e4,n=1e4;function i(){return window.PoolPolicy?.POLICY?.ETH_USD||3500}function r(t){return parseFloat((t/i()).toFixed(6))}function e(t){return parseFloat((t*i()).toFixed(2))}function u(t){const o=Number(t)||0;return o>=1e3?"$"+Math.round(o).toLocaleString():Number.isInteger(o)?"$"+o:"$"+o.toFixed(2)}function s(t){const o=Number(t);if(!Number.isFinite(o)||o<10)throw new Error(`Minimum deposit is ${u(10)}`);if(o>n)throw new Error(`Maximum deposit is ${u(n)}`);return o}return{MIN_TICKET_USD:t,MIN_DEPOSIT_USD:10,MIN_SLOT_BET_USD:1,MIN_ROULETTE_BET_USD:.5,MAX_TICKET_USD:o,MAX_DEPOSIT_USD:n,getEthUsd:i,getEstGasUsd:function(t){const o=window.NetworkFee?.getRange?.(t)||{low:.35,high:12};return(o.low+o.high)/2},getMinCheckoutUsd:function(){return t},usdToEth:r,ethToUsd:e,formatUsd:u,quote:function(n,i){const e=function(n){return Math.min(o,Math.max(t,Math.floor(Number(n)||t)))}(n),u=Math.max(1,Math.floor(Number(i)||1));return{quantity:u,poolUsd:e,gasUsd:0,checkoutUsd:e,checkoutEth:r(e),unitPoolUsd:e/u,minCheckoutUsd:t}},maxCheckoutForWalletUsd:function(n){return n<t?0:Math.min(o,Math.floor(n))},validateDepositUsd:s,validateDepositEth:function(t,o){s(e(t));const n=r(10);if(t<n)throw new Error(`Minimum deposit is ${u(10)} (~${n} ETH)`);return t},validateLotteryEth:function(o){const n=r(t),i=parseFloat(o);if(!Number.isFinite(i)||i<=0)throw new Error("Invalid amount");if(i<n)throw new Error(`Minimum ticket is ${u(t)} (~${n} ETH)`);return i}}})();window.TicketPricing=TicketPricing;
